tabilidade ao girar","type":"radio","options":["Sim","Não"]},{"id":"geri_apoio_externo","label":"Necessidade de apoio externo","type":"radio","options":["Sim","Não"]},{"id":"geri_barreiras_amb","label":"Barreiras ambientais","type":"textarea"},{"id":"geri_tapetes","label":"Tapetes","type":"radio","options":["Sim","Não"]},{"id":"geri_escadas","label":"Escadas","type":"radio","options":["Sim","Não"]},{"id":"geri_iluminacao","label":"Iluminação inadequada","type":"radio","options":["Sim","Não"]},{"id":"geri_risco_class","label":"Risco funcional classificado","type":"select","options":["Baixo","Moderado","Alto"]}]},{"title":"Cognição e comportamento","fields":[{"id":"geri_alt_memoria","label":"Alteração de memória","type":"radio","options":["Sim","Não"]},{"id":"geri_confusao","label":"Confusão","type":"radio","options":["Sim","Não"]},{"id":"geri_def_atencao","label":"Déficit de atenção","type":"radio","options":["Sim","Não"]},{"id":"geri_humor","label":"Humor deprimido","type":"radio","options":["Sim","Não"]},{"id":"geri_ansiedade","label":"Ansiedade","type":"radio","options":["Sim","Não"]},{"id":"geri_lentidao","label":"Lentidão psicomotora","type":"radio","options":["Sim","Não"]},{"id":"geri_comandos","label":"Capacidade de seguir comandos","type":"select","options":["Preservada","Parcial","Ausente"]},{"id":"geri_obs_cognitivas","label":"Observações cognitivas e comportamentais","type":"textarea"}]},{"title":"Exame físico geriátrico funcional","fields":[{"id":"geri_postura","label":"Postura","type":"textarea"},{"id":"geri_marcha_exam","label":"Marcha","type":"textarea"},{"id":"geri_vel_marcha","label":"Velocidade de marcha","type":"text"},{"id":"geri_eq_estatico","label":"Equilíbrio estático","type":"select","options":["Normal","Alterado","Ausente"]},{"id":"geri_eq_dinamico","label":"Equilíbrio dinâmico","type":"select","options":["Normal","Alterado","Ausente"]},{"id":"geri_forca","label":"Força muscular","type":"textarea"},{"id":"geri_oxford","label":"Escala de Oxford","type":"number","placeholder":"0 a 5"},{"id":"geri_adm","label":"Amplitude de movimento","type":"textarea"},{"id":"geri_mob_funcional","label":"Mobilidade funcional","type":"textarea"},{"id":"geri_tolerancia","label":"Tolerância ao esforço","type":"textarea"},{"id":"geri_sensibilidade","label":"Sensibilidade","type":"textarea"},{"id":"geri_coordenacao","label":"Coordenação","type":"textarea"},{"id":"geri_edema","label":"Edema","type":"radio","options":["Sim","Não"]},{"id":"geri_dor","label":"Dor","type":"radio","options":["Sim","Não"]},{"id":"geri_eva","label":"EVA","type":"number","placeholder":"0 a 10"},{"id":"geri_obs_exame","label":"Observações do exame","type":"textarea"}]},{"title":"Diagnóstico funcional geriátrico","fields":[{"id":"geri_diag_cinetico","label":"Diagnóstico cinético-funcional","type":"textarea"},{"id":"geri_risco_queda","label":"Risco de queda","type":"select","options":["Baixo","Moderado","Alto"]},{"id":"geri_deficits","label":"Déficits principais","type":"textarea"},{"id":"geri_limitacoes","label":"Limitações mais relevantes","type":"textarea"},{"id":"geri_barreiras","label":"Barreiras ambientais","type":"textarea"},{"id":"geri_prognostico","label":"Prognóstico funcional","type":"textarea"}]},{"title":"Plano terapêutico geriátrico","fields":[{"id":"geri_obj_autonomia","label":"Objetivo de autonomia","type":"textarea"},{"id":"geri_obj_equilibrio","label":"Objetivo de equilíbrio","type":"textarea"},{"id":"geri_obj_forca","label":"Objetivo de força","type":"textarea"},{"id":"geri_obj_marcha","label":"Objetivo de marcha","type":"textarea"},{"id":"geri_obj_prev_quedas","label":"Objetivo de prevenção de quedas","type":"textarea"},{"id":"geri_estrategia","label":"Estratégia terapêutica","type":"textarea"},{"id":"geri_orient_dom","label":"Orientações domiciliares","type":"textarea"},{"id":"geri_orient_cuidador","label":"Orientações ao cuidador","type":"textarea"},{"id":"geri_frequencia","label":"Frequência sugerida","type":"select","options":["1x/semana","2x/semana","3x/semana","Mais de 3x/semana"]},{"id":"geri_criterios_reav","label":"Critérios de reavaliação","type":"textarea"}]}]'::jsonb
  ];

  FOR i IN 1..3 LOOP
    v_template_id := NULL;
    v_version_id := NULL;

    INSERT INTO public.anamnesis_templates (id, clinic_id, specialty_id, name, description, is_active, is_default, is_system, archived, campos)
    VALUES (gen_random_uuid(), p_clinic_id, p_specialty_id, v_names[i], v_descs[i], true, false, true, false, '[]'::jsonb)
    ON CONFLICT DO NOTHING;

    SELECT id INTO v_template_id FROM public.anamnesis_templates
      WHERE clinic_id = p_clinic_id AND specialty_id = p_specialty_id AND name = v_names[i] LIMIT 1;

    IF v_template_id IS NOT NULL THEN
      IF NOT EXISTS (SELECT 1 FROM public.anamnesis_template_versions WHERE template_id = v_template_id) THEN
        v_version_id := gen_random_uuid();
        INSERT INTO public.anamnesis_template_versions (id, template_id, structure, version_number, version)
        VALUES (v_version_id, v_template_id, v_structures[i], 1, 1);
        UPDATE public.anamnesis_templates SET current_version_id = v_version_id WHERE id = v_template_id;
      END IF;
    END IF;
  END LOOP;
END;
$$;

-- Provision for all existing clinics with fisioterapia
DO $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN
    SELECT DISTINCT c.id AS clinic_id, s.id AS specialty_id
    FROM clinics c
    JOIN specialties s ON s.clinic_id = c.id AND s.slug = 'fisioterapia' AND s.is_active = true
  LOOP
    PERFORM public.provision_fisioterapia_anamnesis_templates(r.clinic_id, r.specialty_id);
  END LOOP;
END;
$$;
